onClick:
{{
  (async () => {
    const SECRET_KEY = "Admin"; // Mật khẩu của bạn

    if (inp_MatKhauXoa.text !== SECRET_KEY) {
      showAlert("❌ Mật khẩu không đúng!", "error");
      return;
    }

    try {
      // 1. Chạy lệnh xóa
      await Action_DeleteAllTools.run();

      showAlert("✅ Đã xóa toàn bộ kho thành công!", "success");

      // 2. LÀM MỚI TẤT CẢ CÁC BẢNG (Để dữ liệu trắng trơn hiện lên)
      await Get_Bang_Tool.run();
      await Get_Inventory_Data.run();
      await Get_LS_Nhap.run();
      await Get_LS_Xuat.run(); // <--- Đảm bảo lệnh này phải có ở đây!

      // 3. Đóng modal và dọn dẹp
      closeModal('Modal_XoaKho');
      resetWidget('inp_MatKhauXoa', true);

    } catch (err) {
      showAlert("❌ Lỗi: " + err.message, "error");
    }
  })()
}}
